import { Component } from '@angular/core';
import { Router, RouterLink } from '@angular/router';
import { FormBuilder, FormGroup, ReactiveFormsModule, Validators } from '@angular/forms';
import { ButtonModule } from 'primeng/button';
import { InputTextModule } from 'primeng/inputtext';
import { PasswordModule } from 'primeng/password';
import { MessageService } from 'primeng/api';

import { firstValueFrom } from 'rxjs';
import { ApiService } from '../../services/api.service';

@Component({
  selector: 'app-cadastro',
  standalone: true,
  imports: [ReactiveFormsModule, RouterLink, ButtonModule, InputTextModule, PasswordModule],
  templateUrl: './cadastro.component.html',
  styleUrl: './cadastro.component.scss',
})
export class CadastroComponent {
  form: FormGroup;
  loading = false;

  constructor(
    private fb: FormBuilder,
    private api: ApiService,
    private router: Router,
    private message: MessageService,
  ) {
    this.form = this.fb.group({
      nome: ['', Validators.required],
      login: ['', Validators.required],
      senha: ['', [Validators.required, Validators.minLength(6)]],
    });
  }

  async onSubmit(): Promise<void> {
    if (this.form.invalid) {
      this.form.markAllAsTouched();
      return;
    }
    this.loading = true;
    try {
      const { nome, login, senha } = this.form.value;
      await firstValueFrom(this.api.post('/usuarios', { nome, login: login.trim(), senha }));
      this.message.add({ severity: 'success', summary: 'Cadastro realizado!', detail: 'Você já pode fazer seu login.' });
      this.router.navigate(['/login']);
    } catch (e: unknown) {
      const msg = e && typeof e === 'object' && 'error' in (e as { error?: { error?: string } })
        ? (e as { error: { error?: string } }).error?.error
        : 'Erro ao fazer cadastro. Tente novamente.';
      this.message.add({ severity: 'error', summary: 'Erro', detail: msg });
    } finally {
      this.loading = false;
    }
  }
}
